def test_sdt_receives_diagnostic_signal():
    from src.coach.sdt import SDTAssessor
    sdt = SDTAssessor({"enabled": True})
    # 模拟诊断信号：连续 3 次正确
    result = sdt.assess(
        conversation_history=["a", "b", "c"],
        recent_performance=[1.0, 1.0, 1.0],
    )
    if result and "competence" in result:
        assert result["competence"] > 0.5  # 表现好→胜任感较高
